event.embedded_functions:

//each function name should be prefixed by em_
/**
 * Return:
 * - 0: ok
 * - 1: invalid
 * - 2: NULL
 */
static inline int em_check_header_http(const char *str){
   const char* c = str;
   while( *c != '\0' ){
      if (*c=='T' && c[1]=='r' && c[2]=='a' && c[3]=='n'){
      	if (strstr(c, "Transfer-Encoding::chunked") != NULL) return 1;
      	// "\\" represents "\"
      	break;
      	} 
     c ++;
  }
  return 0;
}
